"""Check inline ids test."""
import sys
sys.path.insert(0, '/home/vasilyvz/projects/tools/code_analysis')

from code_analysis.core.cst_tree.node_id_inline import strip_inline_stable_ids, restore_inline_stable_ids
import libcst as cst

TEST_FILE = '/home/vasilyvz/projects/tools/cst_mcp_sandbox_20260501/mcp_cst_workspace/test_inline_ids.py'

# 1. Читаем файл с диска - смотрим что там
raw = open(TEST_FILE).read()
lines_with_node_id = [i+1 for i, l in enumerate(raw.splitlines()) if '@node-id' in l]
print('=== DISK STATE ===')
print(f'Total lines: {raw.count(chr(10))+1}')
print(f'Lines with @node-id: {lines_with_node_id}')
if lines_with_node_id:
    for ln in lines_with_node_id:
        print(f'  {ln}: {raw.splitlines()[ln-1]}')
else:
    print('  NONE - inline ids not on disk!')

# 2. Парсируем и проверяем strip
print()
print('=== STRIP TEST ===')
module = cst.parse_module(raw)
clean_module = strip_inline_stable_ids(module)
clean_code = clean_module.code
lines_after_strip = [i+1 for i, l in enumerate(clean_code.splitlines()) if '@node-id' in l]
print(f'Lines with @node-id after strip: {lines_after_strip}')
print('strip OK' if not lines_after_strip else 'strip FAILED - comments remain!')

# 3. Тест restore: берём metadata_map из tree_saver flow
print()
print('=== RESTORE TEST ===')
# Симулируем metadata_map с тестовыми stable_ids
from code_analysis.core.cst_tree.models import TreeNodeMetadata
fake_metadata: dict = {}

# Находим FunctionDef/ClassDef узлы и создаём фейковые метаданные
import uuid

class CollectFuncs(cst.CSTVisitor):
    def __init__(self):
        self.results = []
    def visit_FunctionDef(self, node):
        fake_id = str(uuid.uuid4())
        fake_stable = 'stable-' + node.name.value
        self.results.append((node, fake_id, fake_stable))
    def visit_ClassDef(self, node):
        fake_id = str(uuid.uuid4())
        fake_stable = 'stable-' + node.name.value
        self.results.append((node, fake_id, fake_stable))

visitor = CollectFuncs()
clean_module.walk(visitor)
print(f'Found {len(visitor.results)} FunctionDef/ClassDef nodes')

# Строим fake metadata_map
for node, node_id, stable_id in visitor.results:
    kind = 'class' if isinstance(node, cst.ClassDef) else 'function'
    name = node.name.value
    fake_metadata[node_id] = TreeNodeMetadata(
        node_id=node_id,
        stable_id=stable_id,
        type='FunctionDef' if kind == 'function' else 'ClassDef',
        kind=kind,
        name=name,
        qualname=name,
        start_line=0, start_col=0, end_line=0, end_col=0,
        children_count=0, children_ids=[], parent_id=None,
    )
    print(f'  {kind} {name!r} -> stable_id={stable_id}')

# restore
restored_module = restore_inline_stable_ids(clean_module, fake_metadata)
restored_code = restored_module.code
lines_with_restored = [i+1 for i, l in enumerate(restored_code.splitlines()) if '@node-id' in l]
print(f'Lines with @node-id after restore: {lines_with_restored}')
if lines_with_restored:
    print('restore OK - comments present:')
    for ln in lines_with_restored:
        print(f'  {ln}: {restored_code.splitlines()[ln-1].strip()}')
else:
    print('restore FAILED - no comments added!')

